\label{tab:ppl}
\begin{tabular}{lc}
\toprule
Model & Perplexity \\
\midrule
GPT-2 & 29.4 \\
Transformer-XL & 21.8 \\
Ours & 17.2 \\
\bottomrule
\end{tabular}
\end{table}
