\documentclass{article}
\usepackage[review]{acl}
\begin{document}
\section*{Limitations}

\section{Introduction}
We evaluate on three benchmarks \citep{bender2021parrots}.
Our system achieves F1 of 81.8 on CoNLL-2003 \citep{ye2022generative}.

\section{Experiments}
\begin{table}[h]
\caption{Dataset statistics.}
\label{tab:stats}
\begin{tabular}{lcc}
\toprule
Dataset & Train & Test \\
\midrule
CoNLL-2003 & 14041 & 3684 \\
OntoNotes & 59924 & 8262 \\
\bottomrule
\end{tabular}
\end{table}

\begin{table}[h]
\caption{NER results (F1).}
\label{tab:ner_multi}
\begin{tabular}{lcc}
\toprule
Model & CoNLL-2003 & OntoNotes \\
\midrule
BiLSTM-CRF & 71.1 & 63.4 \\
BERT-NER & 79.3 & 70.2 \\
Ours & 82.1 & 73.8 \\
\bottomrule
\end{tabular}
\end{table}

Our model achieves F1 of 82.1 on CoNLL-2003 \citep{rogers2020primer}.
Figure~\ref{fig:ner_multi} compares models.
\begin{figure}[h]\centering\caption{Multi-dataset NER comparison.}\label{fig:ner_multi}\end{figure}

\bibliography{refs}
\end{document}

